 16→const ENGINE_META: Record<AIEngineId, { name: string; icon: string; color: string; bgClass: string; textClass: string }> = {
 17→  chatgpt: { name: 'ChatGPT', icon: '🟢', color: '#10a37f', bgClass: 'bg-emerald-500/10', textClass: 'text-emerald-400' },
 18→  perplexity: { name: 'Perplexity', icon: '🔵', color: '#20b8cd', bgClass: 'bg-cyan-500/10', textClass: 'text-cyan-400' },
