 22→const CitationDashboardPage: React.FC<Props> = ({ onBack, user, onNavigate }) => {
 23→  const [isRunning, setIsRunning] = useState(false);
 24→  const [progress, setProgress] = useState({ current: 0, total: 0 });
 25→
 26→  const projectId = user?.id || 'default';
 27→  const checks = useMemo(() => getCitationChecks(projectId), [projectId]);
 28→  const queries = useMemo(() => getTrackedQueries(projectId), [projectId]);
 29→  const config = useMemo(() => getProjectConfig(projectId), [projectId]);
 30→
 31→  // Taux de citation agrégés
 32→  const citationRates = useMemo(() => {
 33→    if (checks.length === 0) return null;
 34→    return aggregateCitationRates(checks);
 35→  }, [checks]);
 36→
 37→  // Score de visibilité IA global
 38→  const visibilityScore = useMemo(() => {
 39→    if (!citationRates) return 0;
 40→    const engines: AIEngineId[] = ['chatgpt', 'perplexity', 'gemini'];
 41→    const rates = engines.map(e => citationRates[e]?.citationRatePercent || 0);
 42→    return Math.round(rates.reduce((a, b) => a + b, 0) / rates.length);
 43→  }, [citationRates]);
 44→
 45→  // Dernières 10 citations
 46→  const recentCitations = useMemo(() => {
 47→    return checks
 48→      .filter(c => c.detection.urlExactMatch || c.detection.brandExactMatch || c.detection.urlInSource)
 49→      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
 50→      .slice(0, 10);
 51→  }, [checks]);
