 53→  const handleRunVerification = async () => {
 54→    if (queries.length === 0 || !config) return;
 55→    setIsRunning(true);
 56→    setProgress({ current: 0, total: 1 });
 57→
 58→    try {
 59→      await runCitationChecks(
 60→        queries.filter(q => q.isActive),
 61→        {
 62→          projectId,
 63→          clientUrl: config.clientUrl,
 64→          clientBrand: config.clientBrand,
 65→          brandVariants: config.brandVariants,
 66→          productKeywords: config.productKeywords,
 67→          competitors: [],
 68→        },
 69→        (current, total) => setProgress({ current, total })
 70→      );
