118→        </div>
119→
120→        {/* Zone 2 : Taux de citation par moteur */}
121→        <div className="md:col-span-8 ninja-card p-6 rounded-2xl border border-white/[0.08]">
122→          <h3 className="text-sm font-bold text-white mb-6 flex items-center gap-2">
