136→                      <div className="flex items-center gap-2">
137→                        <span className="text-lg">{meta.icon}</span>
138→                        <span className="text-sm font-medium text-white">{meta.name}</span>
139→                      </div>
140→                      <div className="flex items-center gap-3">
141→                        <span className="text-sm font-bold text-white">{rate.citationRatePercent}%</span>
142→                        <span className={`text-[10px] px-2 py-0.5 rounded-full font-medium ${confidence.class}`}>
143→                          Confiance: {confidence.label}
144→                        </span>
145→                        {getTrendIcon(rate.trend)}
146→                      </div>
147→                    </div>
148→                    <div className="w-full h-2.5 bg-white/10 rounded-full overflow-hidden">
149→                      <div
150→                        className="h-full rounded-full transition-all duration-700 ease-out"
151→                        style={{ width: `${rate.citationRatePercent}%`, backgroundColor: meta.color }}
152→                      />
153→                    </div>
154→                    <div className="flex justify-between mt-1">
155→                      <span className="text-[10px] text-gray-600">{rate.citationsDetected}/{rate.totalChecks} détections</span>
156→                      <span className="text-[10px] text-gray-600">Score moyen: {rate.avgCitationScore}</span>
157→                    </div>
158→                  </div>
159→                );
160→              })}
161→            </div>
162→          ) : (
163→            <div className="flex flex-col items-center justify-center py-8 text-center">
164→              <Radar size={40} className="text-gray-600 mb-3" />
165→              <p className="text-sm text-gray-500 mb-1">Aucune donnée de citation disponible</p>
166→              <p className="text-xs text-gray-600">Configurez vos requêtes cibles et lancez une vérification.</p>
167→            </div>
168→          )}
169→        </div>
170→      </div>
171→
172→      {/* Zone 4 : Dernières détections */}
173→      <div className="ninja-card rounded-2xl border border-white/[0.08] mb-8 overflow-hidden">
174→        <div className="p-6 border-b border-white/[0.08] flex justify-between items-center bg-white/[0.04]">
175→          <h3 className="font-bold text-white flex items-center gap-2">
176→            <Clock size={18} className="text-gray-500" />
177→            Dernières citations détectées
178→          </h3>
179→          <span className="text-xs text-gray-500">{recentCitations.length} résultat{recentCitations.length > 1 ? 's' : ''}</span>
180→        </div>
181→
182→        {recentCitations.length > 0 ? (
183→          <div className="divide-y divide-white/5">
184→            {recentCitations.map((check) => {
185→              const meta = ENGINE_META[check.engine];
186→              return (
187→                <div key={check.id} className="px-6 py-4 hover:bg-white/[0.02] transition-colors">
188→                  <div className="flex items-start gap-3">
189→                    <span className={`text-xs font-medium px-2 py-1 rounded-full ${meta.bgClass} ${meta.textClass} shrink-0 mt-0.5`}>
190→                      {meta.icon} {meta.name}
191→                    </span>
192→                    <div className="flex-1 min-w-0">
193→                      <p className="text-sm text-white truncate">&quot;{check.promptSent}&quot;</p>
194→                      <div className="flex items-center gap-3 mt-1">
195→                        <span className="text-xs text-gray-500">
196→                          Score: <span className="text-white font-medium">{check.detection.citationScore}</span>
197→                        </span>
198→                        <span className="text-xs text-gray-600">
199→                          {check.detection.positionInResponse === 'first_paragraph' ? 'Premier paragraphe' :
200→                           check.detection.positionInResponse === 'middle' ? 'Milieu de réponse' :
201→                           check.detection.positionInResponse === 'end' ? 'Fin de réponse' : 'Footnote'}
202→                        </span>
203→                        <span className={`text-xs ${
204→                          check.detection.sentiment === 'positive' ? 'text-green-400' :
205→                          check.detection.sentiment === 'negative' ? 'text-red-400' : 'text-gray-500'
206→                        }`}>
207→                          {check.detection.sentiment === 'positive' ? '👍 Positif' :
208→                           check.detection.sentiment === 'negative' ? '👎 Négatif' : '🔘 Neutre'}
209→                        </span>
210→                      </div>
211→                    </div>
212→                    <span className="text-[10px] text-gray-600 shrink-0">
213→                      {new Date(check.createdAt).toLocaleDateString()}
214→                    </span>
215→                  </div>
216→                </div>
217→              );
218→            })}
219→          </div>
220→        ) : (
221→          <div className="px-6 py-10 text-center text-gray-500 text-sm">
222→            Aucune citation détectée pour le moment. Lancez une vérification pour commencer.
223→          </div>
224→        )}
225→      </div>
226→
227→      {/* Zone 5 : Actions */}
228→      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
229→        <button
230→          onClick={handleRunVerification}
231→          disabled={isRunning || queries.length === 0}
232→          className="ninja-card p-5 rounded-2xl border border-cyan-500/20 hover:border-cyan-500/40 transition-all flex items-center gap-4 group disabled:opacity-50 disabled:cursor-not-allowed"
233→        >
234→          <div className="w-10 h-10 rounded-full bg-cyan-500/20 flex items-center justify-center text-cyan-400 group-hover:scale-110 transition-transform">
235→            <Play size={18} />
236→          </div>
237→          <div className="text-left">
238→            <p className="text-sm font-bold text-white">
239→              {isRunning ? `Vérification en cours (${progress.current}/${progress.total})` : 'Lancer une vérification'}
240→            </p>
241→            <p className="text-xs text-gray-500">
242→              {queries.filter(q => q.isActive).length} requêtes actives
243→            </p>
244→          </div>
245→        </button>
246→
247→        <button
248→          onClick={() => onNavigate('tracked-queries')}
249→          className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-purple-500/30 transition-all flex items-center gap-4 group"
250→        >
251→          <div className="w-10 h-10 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-400 group-hover:scale-110 transition-transform">
252→            <Target size={18} />
253→          </div>
254→          <div className="text-left">
255→            <p className="text-sm font-bold text-white">Gérer les requêtes</p>
